```javascript
class Cooldown {
  /**
   * Creates a new cooldown timer.
   * @param {number} duration - The duration of the cooldown in milliseconds.
   */
  constructor(duration) {
    this.duration = duration;
    this.lastActivated = null;
  }

  /**
   * Checks if the cooldown has expired.
   * @returns {boolean} True if the cooldown has expired, false otherwise.
   */
  hasExpired() {
    if (this.lastActivated === null) return true;
    const now = Date.now();
    const elapsed = now - this.lastActivated;
    return elapsed >= this.duration;
  }

  /**
   * Activates the cooldown and resets the timer.
   */
  activate() {
    this.lastActivated = Date.now();
  }
